begin;

-- 0) إزالة أعمدة التحضير والملاحظات إن وُجدت
alter table public.tests drop column if exists preparation_ar;
alter table public.tests drop column if exists preparation_en;
alter table public.tests drop column if exists limitation_note_ar;
alter table public.tests drop column if exists limitation_note_en;

-- 1) حذف الفحوصات القديمة
delete from public.tests;

-- 2) التأكد من التصنيفات
insert into public.test_categories (slug, title_ar, title_en, sort_order)
values
  ('immunohistochemistry', 'Immunohistochemistry', 'Immunohistochemistry', 1),
  ('oncology_somatic', 'Oncology', 'Oncology', 2),
  ('hereditary_cancer', 'Hereditary Cancer Genetics', 'Hereditary Cancer Genetics', 3),
  ('reproductive', 'Reproductive Health', 'Reproductive Health', 4),
  ('nipt', 'Non-Invasive Prenatal Testing (NIPT)', 'Non-Invasive Prenatal Testing (NIPT)', 5),
  ('pediatric_newborn', 'Pediatric', 'Pediatric', 6)
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  sort_order = excluded.sort_order;


-- 3) إدراج القائمة الجديدة
insert into public.tests (
  slug, category, title_ar, title_en, description_ar, description_en,
  long_description_ar, long_description_en,
  clinical_use_ar, clinical_use_en, sample_ar, sample_en,
  method_ar, method_en, turnaround_ar, turnaround_en,
  price_display_ar, price_display_en, image_url, sort_order
) values
('slide-review', 'immunohistochemistry', 'Slide review', 'Slide review', 'مراجعة مجهرية للشرائح النسيجية والعينات المقدمة بواسطة اختصاصي علم الأمراض لتأكيد التشخيص أو تدقيقه.', 'Microscopic review of submitted histopathology slides and tissue material by a pathologist to confirm or refine the diagnosis.', 'مراجعة مجهرية للشرائح النسيجية والعينات المقدمة بواسطة اختصاصي علم الأمراض لتأكيد التشخيص أو تدقيقه.', 'Microscopic review of submitted histopathology slides and tissue material by a pathologist to confirm or refine the diagnosis.', 'يُستخدم لتأكيد التشخيص النسيجي أو الحصول على رأي ثانٍ أو تدقيق الدرجة المرضية قبل إجراء فحوص إضافية أو بدء العلاج.', 'Used for expert confirmation of a histopathology diagnosis, second opinion, grading, or clarification before further testing or treatment.', 'Tissue Block (FFPE)', 'Tissue Block (FFPE)', 'مراجعة نسيجية مجهرية', 'Microscopic histopathology review', '10 ايام', '10 Days', 'السعر القائمة: 70٬000 د.ع', 'List price: 70,000 IQD', null, 1),
('immunohistochemistry-pdl-1', 'immunohistochemistry', 'Immunohistochemistry (PDL-1)', 'Immunohistochemistry (PDL-1)', 'تقييم التعبير البروتيني لـ PD-L1 في النسيج الورمي باستخدام الصبغ المناعي النسيجي على منصة آلية معتمدة.', 'Immune-checkpoint inhibitor therapies', 'تقييم التعبير البروتيني لـ PD-L1 في النسيج الورمي باستخدام الصبغ المناعي النسيجي على منصة آلية معتمدة.', 'Immune-checkpoint inhibitor therapies', 'يُستخدم لتقييم أهلية المريض لبعض العلاجات المثبطة لنقاط التفتيش المناعية وفق نوع الورم ونظام التقييم المعتمد.', 'Used to assess eligibility for selected immune-checkpoint inhibitor therapies according to the tumor type and approved scoring criteria.', 'Tissue Block (FFPE)', 'Tissue Block (FFPE)', 'IHC by VENTANA', 'IHC by VENTANA', '10 ايام', '10 Days', 'السعر القائمة: 350٬000 د.ع', 'List price: 350,000 IQD', null, 2),
('ihc-marker', 'immunohistochemistry', 'IHC Marker', 'IHC Marker', 'صبغ مناعي نسيجي لواسم مختار لتقييم التعبير البروتيني والمساعدة في التصنيف المرضي.', 'Immunohistochemical staining for a selected tissue marker to evaluate protein expression and support pathological classification.', 'صبغ مناعي نسيجي لواسم مختار لتقييم التعبير البروتيني والمساعدة في التصنيف المرضي.', 'Immunohistochemical staining for a selected tissue marker to evaluate protein expression and support pathological classification.', 'يُستخدم للمساعدة في تصنيف الورم وتحديد منشئه وتقييم الواسمات الإنذارية أو التنبؤية.', 'Used to support tumor classification, determine tissue of origin, assess prognostic markers, or evaluate predictive biomarkers.', 'Tissue Block (FFPE)', 'Tissue Block (FFPE)', 'IHC', 'IHC', '10 ايام', '10 Days', 'السعر القائمة: 70٬000 د.ع', 'List price: 70,000 IQD', null, 3),
('mmr', 'immunohistochemistry', 'Mismatch Repair (MMR)', 'Mismatch Repair (MMR)', 'تقييم مناعي نسيجي لبروتينات إصلاح عدم التطابق MLH1 وPMS2 وMSH2 وMSH6 في النسيج الورمي.', 'Immunohistochemical evaluation of the mismatch-repair proteins MLH1, PMS2, MSH2, and MSH6 in tumor tissue.', 'تقييم مناعي نسيجي لبروتينات إصلاح عدم التطابق MLH1 وPMS2 وMSH2 وMSH6 في النسيج الورمي.', 'Immunohistochemical evaluation of the mismatch-repair proteins MLH1, PMS2, MSH2, and MSH6 in tumor tissue.', 'يُستخدم لتحري عوز إصلاح عدم التطابق ودعم تقييم متلازمة لينش وتحديد أورام قد تستفيد من العلاج المناعي.', 'Used to screen for mismatch-repair deficiency, support Lynch syndrome evaluation, and help identify tumors that may benefit from immunotherapy.', 'Tissue Block (FFPE)', 'Tissue Block (FFPE)', 'IHC', 'IHC', '10 ايام', '10 Days', 'السعر القائمة: 400٬000 د.ع', 'List price: 400,000 IQD', null, 4),
('her2-neu-amp-ish', 'immunohistochemistry', 'HER2/NEU amp, ISH', 'HER2/NEU amp, ISH', 'تقييم تضخّم جين ERBB2 ‏(HER2) في النسيج الورمي باستخدام التهجين الموضعي.', 'HER2 amplification', 'تقييم تضخّم جين ERBB2 ‏(HER2) في النسيج الورمي باستخدام التهجين الموضعي.', 'HER2 amplification', 'يُستخدم لتأكيد تضخّم HER2 ودعم اختيار العلاج الموجّه ضد HER2 في الأورام المناسبة.', 'Used to confirm HER2 amplification and support selection of HER2-targeted therapy in relevant cancers.', 'Tissue Block (FFPE)', 'Tissue Block (FFPE)', 'IHC by VENTANA', 'IHC by VENTANA', '10 ايام', '10 Days', 'السعر القائمة: 450٬000 د.ع', 'List price: 450,000 IQD', null, 5),
